1	// claim-office.ts
2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Step = {
15	  op: string;
16	  items?: Item[];
17	};
18	
19	type ScenarioInput = {
20	  customer: Customer;
21	  steps: Step[];
22	};
23	
24	type ScenarioOutput = {
25	  results: unknown[];
26	};
27	
28	const PROCESSING_FEE = 5;
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
36	const COMPONENT_BLOCK_SIZE = 3;
37	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
38	
39	const BASE_PREMIUMS: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	
50	const isComponentBlock = (type: string, count: number): boolean =>
51	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
52	
53	const basePremiumFor = (type: string): number => {
54	  const basePremium = BASE_PREMIUMS[type];
55	  if (basePremium === undefined) {
56	    throw new Error(`Unknown item type: ${type}`);
57	  }
58	  return basePremium;
59	};
60	
61	const surchargeFor = (
62	  items: Item[],
63	  applies: (item: Item) => boolean,
64	  rate: number
65	): number =>
66	  items.reduce(
67	    (surcharge, item) =>
68	      applies(item) ? surcharge + basePremiumFor(item.type) * rate : surcharge,
69	    0
70	  );
71	
72	const isCursed = (item: Item): boolean => item.cursed === true;
73	
74	const isHighlyEnchanted = (item: Item): boolean =>
75	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
76	
77	const curseSurchargeFor = (items: Item[]): number =>
78	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
79	
80	const enchantmentSurchargeFor = (items: Item[]): number =>
81	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
82	
83	const groupBasePremium = (type: string, count: number): number =>
84	  isComponentBlock(type, count)
85	    ? COMPONENT_BLOCK_BASE_PREMIUM
86	    : count * basePremiumFor(type);
87	
88	const policyBaseFor = (items: Item[]): number => {
89	  const countsByType = new Map<string, number>();
90	  for (const item of items) {
91	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
92	  }
93	
94	  let policyBase = 0;
95	  for (const [type, count] of countsByType) {
96	    policyBase += groupBasePremium(type, count);
97	  }
98	  return policyBase;
99	};
100	
101	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
102	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
103	
104	const quotePremium = (
105	  items: Item[],
106	  customer: Customer,
107	  isFollowUp: boolean
108	): number => {
109	  const policyBase = policyBaseFor(items);
110	  const itemSurcharges =
111	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
112	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
113	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
114	    ? policyBase * LOYALTY_DISCOUNT_RATE
115	    : 0;
116	  const followUpDiscount = isFollowUp
117	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
118	    : 0;
119	  return Math.ceil(
120	    policyBase +
121	      itemSurcharges +
122	      firstInsuranceSurcharge -
123	      loyaltyDiscount -
124	      followUpDiscount +
125	      PROCESSING_FEE
126	  );
127	};
128	
129	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
130	
131	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
132	  const results = input.steps.map((step, index) => ({
133	    premium: quotePremium(step.items ?? [], input.customer, isFollowUpQuote(index)),
134	  }));
135	  return { results };
136	};
